### Change 3: Add `validateDeploymentManifest` function

Add this function after the `updateVolumeWithIssuerCA` function (after line 484):

```go
// validateDeploymentManifest checks that the deployment contains the expected
// container and CA volume. Without these, the update helpers silently no-op
// and the operator would apply a deployment with stale defaults.
func validateDeploymentManifest(deployment *appsv1.Deployment) error {
	hasContainer := false
	for _, c := range deployment.Spec.Template.Spec.Containers {
		if c.Name == istiocsrContainerName {
			hasContainer = true
			break
		}
	}
	if !hasContainer {
		return fmt.Errorf("deployment manifest missing required container %q", istiocsrContainerName)
	}

	hasVolume := false
	for _, v := range deployment.Spec.Template.Spec.Volumes {
		if v.Name == caVolumeName {
			hasVolume = true
			break
		}
	}
	if !hasVolume {
		return fmt.Errorf("deployment manifest missing required volume %q", caVolumeName)
	}

	return nil
}
```

